import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote — single item base premiums (R1)", () => {
    it.todo("amulet alone → base premium 60 G (before fee, no other modifiers)");
    it.todo("sword alone → base premium 100 G");
    it.todo("staff alone → base premium 80 G");
    it.todo("potion alone → base premium 40 G");
    it.todo("a single rune → base premium 25 G");
    it.todo("empty item list → premium 5 G (processing fee only)");
  });

  describe("quote — component building blocks (R2, R3)", () => {
    it.todo("2 runes → base premium 50 G (below block size, 2×25)");
    it.todo("3 runes → base premium 60 G (block of exactly 3 applies)");
    it.todo("4 runes → base premium 100 G (no block — block requires exactly 3, 4×25)");
    it.todo("7 runes → base premium 175 G (no block — 7×25)");
    it.todo("2 runes + 1 moonstone → base premium 75 G (no block: different types, 3×25)");
    it.todo("3 runes + 3 moonstones → base premium 120 G (two separate blocks, 60 + 60)");
  });

  describe("quote — premium modifiers and scope (R4, R5)", () => {
    it.todo("cursed sword adds 50% to the item base premium → 150 G base+surcharge (before policy modifiers and fee)");
    it.todo("sword with enchantment exactly 5 → high-enchantment 30% surcharge applies");
    it.todo("sword with enchantment 4 → no high-enchantment surcharge");
    it.todo("customer with exactly 2 years → 20% loyalty discount applies");
    it.todo("policy with cursed sword (100) + plain amulet (60) → 210 G before policy-wide modifiers and fee (cursed surcharge 50 = 50% of sword base only)");
  });

  describe("quote — integration examples (R4, R5, R8)", () => {
    it.todo("newcomer (0 yrs), cursed sword (steel, ench 3) → premium 165 G (100 base + 50 curse + 10 first-insurance + 5 fee)");
    it.todo("long-standing customer (3 yrs), second quote, cursed sword (steel, ench 7) → premium 160 G (100 + 50 curse + 30 high-ench − 20 loyalty + 10 first-ins − 15 follow-up + 5 fee)");
    it.todo("premium that computes to 197.5 G → rounded up to 198 G (MHPCO favor)");
  });

  describe("claim — standard reimbursement and clauses (R7)", () => {
    it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (500 − 100 deductible)");
    it.todo("rune (insurance value 250 G), damage 200 G → payout 100 G (200 − 100, no special clause)");
    it.todo("dragon-material sword, enchantment exactly 8, damage 1000 G → payout 400 G (50% clause then deductible: 500 − 100)");
    it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (dragon full reimbursement then deductible: 800 − 100)");
    it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (high-ench 50% then deductible: 500 − 100)");
    it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins over dragon, then deductible)");
    it.todo("dragon attack: sword damaged 500 G + amulet damaged 300 G → payout 600 G (100 G deductible per damaged item)");
    it.todo("payout that computes to 350.5 G → rounded down to 350 G (MHPCO favor)");
  });

  describe("claim — caps and exhaustion (R7)", () => {
    it.todo("sword + amulet → insurance sum 1600 G, cap 3200 G (2× sum of insurance values)");
    it.todo("cursed sword (value 1000, premium 165) → cap 2000 G (based on unmodified insurance value)");
    it.todo("sword + 3 runes (block) → insurance sum 1750 G (1000 + 3×250; block discount affects premium only)");
    it.todo("sword (cap 2000), two successive 1500 G claims → first payout 1400 G (remaining cap 600), second payout 600 G (remaining cap 0)");
    it.todo("two swords → insurance sum 2000 G, cap 4000 G");
    it.todo("two swords both damaged (two sword damage entries) → each treated as separate damage with its own 100 G deductible");
  });
});

describe("MHPCO Claim Office — CLI (src/cli.ts via stdin/stdout)", () => {
  it.todo("CLI reads a JSON scenario from stdin and writes {results:[...]} with a premium integer for a quote step");
  it.todo("CLI writes payout and remainingCap integers for a claim step result, in step order");
  it.todo("CLI exits with non-zero status and writes error to stderr (no results on stdout) when a quote item has an unknown type (e.g. broomstick)");
  it.todo("CLI exits with non-zero status when a claim references an item not in the policy (e.g. amulet damaged when only a sword is insured)");
  it.todo("CLI exits with non-zero status when a damage entry has a negative amount (e.g. -200)");
  it.todo("CLI exits with non-zero status when damages contain more entries of a type than the policy covers (two sword damages, one sword insured)");
});
